class Solution {
public:
    bool hasAlternatingBits(int n) {
        bool prevBit = n & 1;
        n >>= 1;
        while (n > 0) {
            bool currentBit = n & 1;
            if (currentBit == prevBit) {
                return false;
            }
            prevBit = currentBit;
            n >>= 1;
        }
        return true;
    }
};
```
